     1→<?php
     2→/**
     3→ * Database Singleton Class
     4→ * Provides a single PDO database connection instance throughout the application
     5→ */
     6→
     7→class Database {
     8→    private static $instance = null;
     9→    private $connection;
    10→
    11→    // Database configuration
    12→    private $host = 'localhost';
    13→    private $dbname = 'vibe_templates';
    14→    private $username = 'vibe_templates';
    15→    private $password = '#Skilliks229!';
    16→    private $charset = 'utf8mb4';
    17→
    18→    /**
    19→     * Private constructor to prevent direct instantiation
    20→     */
    21→    private function __construct() {
    22→        try {
    23→            $dsn = "mysql:host={$this->host};dbname={$this->dbname};charset={$this->charset}";
    24→
    25→            $options = [
    26→                PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
    27→                PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
    28→                PDO::ATTR_EMULATE_PREPARES => false,
    29→                PDO::ATTR_PERSISTENT => true
    30→            ];
    31→
    32→            $this->connection = new PDO($dsn, $this->username, $this->password, $options);
    33→
    34→        } catch (PDOException $e) {
    35→            error_log("Database connection failed: " . $e->getMessage());
    36→            throw new Exception("Database connection error: Unable to connect to database");
    37→        }
    38→    }
    39→
    40→    /**
    41→     * Get the singleton instance
    42→     * @return Database
    43→     */
    44→    public static function getInstance() {
    45→        if (self::$instance === null) {
    46→            self::$instance = new self();
    47→        }
    48→        return self::$instance;
    49→    }
    50→
    51→    /**
    52→     * Get the PDO connection
    53→     * @return PDO
    54→     */
    55→    public function getConnection() {
    56→        return $this->connection;
    57→    }
    58→
    59→    /**
    60→     * Prepare and execute a query with parameters
    61→     * @param string $sql SQL query
    62→     * @param array $params Parameters to bind
    63→     * @return PDOStatement
    64→     */
    65→    public function query($sql, $params = []) {
    66→        try {
    67→            $stmt = $this->connection->prepare($sql);
    68→            $stmt->execute($params);
    69→            return $stmt;
    70→        } catch (PDOException $e) {
    71→            error_log("Query failed: " . $e->getMessage());
    72→            throw new Exception("Query execution error");
    73→        }
    74→    }
    75→
    76→    /**
    77→     * Get last insert ID
    78→     * @return string
    79→     */
    80→    public function lastInsertId() {
    81→        return $this->connection->lastInsertId();
    82→    }
    83→
    84→    /**
    85→     * Begin transaction
    86→     */
    87→    public function beginTransaction() {
    88→        return $this->connection->beginTransaction();
    89→    }
    90→
    91→    /**
    92→     * Commit transaction
    93→     */
    94→    public function commit() {
    95→        return $this->connection->commit();
    96→    }
    97→
    98→    /**
    99→     * Rollback transaction
   100→     */
   101→    public function rollback() {
   102→        return $this->connection->rollBack();
   103→    }
   104→
   105→    /**
   106→     * Check if connected
   107→     * @return boolean
   108→     */
   109→    public function isConnected() {
   110→        try {
   111→            $this->connection->query('SELECT 1');
   112→            return true;
   113→        } catch (PDOException $e) {
   114→            return false;
   115→        }
   116→    }
   117→
   118→    /**
   119→     * Prevent cloning of the instance
   120→     */
   121→    private function __clone() {}
   122→
   123→    /**
   124→     * Prevent unserializing of the instance
   125→     */
   126→    public function __wakeup() {
   127→        throw new Exception("Cannot unserialize singleton");
   128→    }
   129→}

